import axios from "axios";

// 1. Configuración de la instancia base
const api = axios.create({
  baseURL: "http://localhost:5000/api", // Asegúrate de que este puerto coincida con tu backend
  timeout: 15000, // 15 segundos de espera máximo (útil para subir imágenes)
  headers: {
    "Content-Type": "application/json",
  },
});

// 2. Interceptor de Peticiones
// Este bloque es fundamental: si el usuario está logueado, 
// extrae el token del localStorage y lo pega en los headers de cada consulta.
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("token");
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// 3. Interceptor de Respuestas (Opcional pero recomendado)
// Si el servidor responde con un 401 (No autorizado), podrías redirigir al login
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response && error.response.status === 401) {
      console.warn("Token expirado o no autorizado. Redirigiendo...");
      // Aquí podrías hacer: window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);
// En tu componente de React
const data = {
  nombre: nombreInput, // Usa minúsculas aquí
  descripcion: descripcionInput
};
await api.post("/categorias", data);

export default api;
